# ─────────────────────────────────────────────────────────────
# UTILS
# ─────────────────────────────────────────────────────────────

def safe_float(v, default=0.0):
    if v is None: return float(default)
    try:
        if np.isnan(v): return float(default)
    except: pass
    return float(v)

def order_corners(corners):
    corners = np.array(corners, dtype=np.float32)
    tl = corners[np.argmin(corners[:,0] + corners[:,1])]
    tr = corners[np.argmax(corners[:,0] - corners[:,1])]
    br = corners[np.argmax(corners[:,0] + corners[:,1])]
    bl = corners[np.argmin(corners[:,0] - corners[:,1])]
    return np.array([tl, tr, br, bl], dtype=np.float32)

def label_to_base_colour(label):
    if label == "cue":    return "white"
    if label == "black":  return "black"
    if "_solid"  in label: return label.replace("_solid","")
    if "_stripe" in label: return label.replace("_stripe","")
    return None

def label_to_ball_type(label):
    if label == "cue":    return "cue"
    if label == "black":  return "black"
    if "_solid"  in label: return "solid"
    if "_stripe" in label: return "stripe"
    return None

def final_label_from_parts(colour, btype):
    if colour == "white": return "cue"
    if colour == "black": return "black"
    if colour is None or btype is None: return "not_ball"
    return f"{colour}_{btype}"

# ─────────────────────────────────────────────────────────────
# SVM INFERENCE (numpy only)
# ─────────────────────────────────────────────────────────────

def _rbf_kernel(sv, xz, gamma):
    diff = sv - xz
    return np.exp(-gamma * np.sum(diff**2, axis=1))

def _sigmoid_prob(decision, probA, probB):
    fApB = decision * probA + probB
    return np.where(fApB >= 0,
        np.exp(-fApB) / (1 + np.exp(-fApB)),
        1.0 / (1 + np.exp(fApB)))

def svm_predict_colour(feat_vec):
    xz     = (feat_vec[_FEAT_INDICES] - _SVM_C_FEAT_MEAN) / _SVM_C_FEAT_STD
    K      = _rbf_kernel(_SVM_C_SV, xz, _SVM_C_GAMMA)
    scores = _SVM_C_DCOEF @ K + _SVM_C_INTERCEPT
    pair_p = _sigmoid_prob(scores, _SVM_C_PROBA, _SVM_C_PROBB)
    n      = len(_SVM_C_CLASSES)
    votes  = np.zeros(n)
    idx = 0
    for i in range(n):
        for j in range(i+1, n):
            votes[i] += pair_p[idx]; votes[j] += 1 - pair_p[idx]; idx += 1
    votes /= votes.sum() + 1e-9
    order  = np.argsort(votes)[::-1]
    return [(str(_SVM_C_CLASSES[k]), float(votes[k])) for k in order]

def svm_predict_type(feat_vec):
    xz    = (feat_vec[_FEAT_INDICES] - _SVM_T_FEAT_MEAN) / _SVM_T_FEAT_STD
    K     = _rbf_kernel(_SVM_T_SV, xz, _SVM_T_GAMMA)
    score = float((_SVM_T_DCOEF @ K + _SVM_T_INTERCEPT)[0])
    p     = float(_sigmoid_prob(np.array([score]), _SVM_T_PROBA, _SVM_T_PROBB)[0])
    if _SVM_T_CLASSES[0] == "solid":
        return [("solid", p), ("stripe", 1-p)]
    return [("stripe", p), ("solid", 1-p)]

# ─────────────────────────────────────────────────────────────
# FEATURE EXTRACTION
# ─────────────────────────────────────────────────────────────

def build_inner_circle_mask(shape):
    h, w = shape[:2]
    mask = np.zeros((h,w), dtype=np.uint8)
    cv2.circle(mask, (w//2, h//2), int(min(w//2,h//2)*INNER_RADIUS_FACTOR), 255, -1)
    return mask

def compute_stripe_score(roi):
    h, w = roi.shape[:2]; cx, cy = w//2, h//2
    ri = int(min(cx,cy)*0.45); ro = int(min(cx,cy)*0.75)
    mi = np.zeros((h,w),dtype=np.uint8); cv2.circle(mi,(cx,cy),ri,255,-1)
    mo = np.zeros((h,w),dtype=np.uint8); cv2.circle(mo,(cx,cy),ro,255,-1)
    mr = cv2.bitwise_and(mo, cv2.bitwise_not(mi))
    hsv = cv2.cvtColor(roi, cv2.COLOR_BGR2HSV)
    wm  = cv2.inRange(hsv, WHITE_LOW, WHITE_HIGH)
    wc  = cv2.countNonZero(cv2.bitwise_and(wm,mi)) / max(cv2.countNonZero(mi),1)
    wr  = cv2.countNonZero(cv2.bitwise_and(wm,mr)) / max(cv2.countNonZero(mr),1)
    return float(wr-wc), float(wc), float(wr)

def compute_patch_statistics(roi):
    if roi is None or roi.size == 0: return None
    hsv  = cv2.cvtColor(roi, cv2.COLOR_BGR2HSV)
    cm   = build_inner_circle_mask(roi.shape)
    wm   = cv2.bitwise_and(cv2.inRange(hsv,WHITE_LOW,WHITE_HIGH), cm)
    bm   = cv2.bitwise_and(cv2.inRange(hsv,BLACK_LOW,BLACK_HIGH), cm)
    colm = cv2.bitwise_and(cm, cv2.bitwise_not(cv2.bitwise_or(wm,bm)))
    tot  = max(cv2.countNonZero(cm),1)
    wp   = cv2.countNonZero(wm); bp = cv2.countNonZero(bm); cp = cv2.countNonZero(colm)
    stats = {"white_ratio": wp/tot, "black_ratio": bp/tot, "colour_ratio": cp/tot}
    if cp > 0:
        hv = hsv[:,:,0][colm>0].astype(float)
        sv = hsv[:,:,1][colm>0].astype(float)
        vv = hsv[:,:,2][colm>0].astype(float)
        stats.update({
            "h_median": float(np.median(hv)), "s_median": float(np.median(sv)),
            "v_median": float(np.median(vv)), "h_std": float(np.std(hv)),
            "s_p90": float(np.percentile(sv,90)), "v_p90": float(np.percentile(vv,90)),
            "v_std": float(np.std(vv)), "h_p10": float(np.percentile(hv,10)),
            "h_p90": float(np.percentile(hv,90)), "s_p10": float(np.percentile(sv,10)),
            "v_p10": float(np.percentile(vv,10)),
        })
    else:
        for k in ["h_median","s_median","v_median","h_std","s_p90","v_p90",
                  "v_std","h_p10","h_p90","s_p10","v_p10"]:
            stats[k] = None
    ss, rc, rr = compute_stripe_score(roi)
    stats["stripe_score"] = ss
    stats["white_ratio_center"] = rc
    stats["white_ratio_ring"]   = rr
    return stats

def get_feature_vector(stats):
    h = stats.get("h_median")
    if h is None: hc, hs = 0.0, 0.0
    else:
        a = 2*np.pi*float(h)/180; hc, hs = np.cos(a), np.sin(a)
    return np.array([
        hc, hs,
        safe_float(stats.get("s_median")),  safe_float(stats.get("v_median")),
        safe_float(stats.get("white_ratio")),safe_float(stats.get("black_ratio")),
        safe_float(stats.get("colour_ratio")),safe_float(stats.get("h_std")),
        safe_float(stats.get("v_p90")),     safe_float(stats.get("v_std")),
        safe_float(stats.get("s_p90")),     safe_float(stats.get("stripe_score")),
        safe_float(stats.get("h_p10")),     safe_float(stats.get("h_p90")),
        safe_float(stats.get("s_p10")),     safe_float(stats.get("v_p10")),
        safe_float(stats.get("white_ratio_center")),
        safe_float(stats.get("white_ratio_ring")),
    ], dtype=float)

def crop_ball_roi(img, x, y, r):
    h, w = img.shape[:2]; rr = int(round(r*ROI_PAD))
    x1,y1 = max(0,int(x-rr)), max(0,int(y-rr))
    x2,y2 = min(w,int(x+rr)), min(h,int(y+rr))
    return img[y1:y2, x1:x2].copy()

# ─────────────────────────────────────────────────────────────
# TABLE SEGMENTATION & TOP VIEW
# ─────────────────────────────────────────────────────────────

def segment_table(img):
    hsv  = cv2.cvtColor(img, cv2.COLOR_BGR2HSV)
    mask = cv2.bitwise_or(
        cv2.inRange(hsv, np.array([90,80,50]),  np.array([130,255,255])),
        cv2.inRange(hsv, np.array([35,80,50]),  np.array([85,255,255])),
    )
    contours,_ = cv2.findContours(mask, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
    tc  = max(contours, key=cv2.contourArea)
    eps = 0.02 * cv2.arcLength(tc, True)
    app = cv2.approxPolyDP(tc, eps, True)
    corners = app.reshape(4,2).astype(np.float32) if len(app)==4               else cv2.boxPoints(cv2.minAreaRect(tc)).astype(np.float32)
    corners = order_corners(corners)
    clean   = np.zeros(img.shape[:2], dtype=np.uint8)
    cv2.fillPoly(clean, [corners.astype(np.int32)], 255)
    return clean, corners

def get_top_view(img, corners, expand_px=20):
    center = corners.mean(0)
    exp = np.array([pt + (pt-center)/max(np.linalg.norm(pt-center),1e-9)*expand_px
                    for pt in corners], dtype=np.float32)
    tl,tr,br,bl = exp
    W = int(max(np.linalg.norm(tr-tl), np.linalg.norm(br-bl)))
    H = int(W * 2.0)
    dst = np.array([[0,0],[W-1,0],[W-1,H-1],[0,H-1]], dtype=np.float32)
    M   = cv2.getPerspectiveTransform(exp, dst)
    warped = cv2.warpPerspective(img, M, (W,H))
    if warped.shape[0] > warped.shape[1]:
        warped = cv2.rotate(warped, cv2.ROTATE_90_CLOCKWISE)
    return warped

# ─────────────────────────────────────────────────────────────
# BALL DETECTION
# ─────────────────────────────────────────────────────────────

def detect_balls(img, mask):
    masked  = cv2.bitwise_and(img, img, mask=mask)
    hsv     = cv2.cvtColor(masked, cv2.COLOR_BGR2HSV)
    h_,s_,v_ = cv2.split(hsv)
    s_ = cv2.convertScaleAbs(s_, alpha=1.35, beta=10)
    v_ = cv2.convertScaleAbs(v_, alpha=1.15, beta=8)
    mb  = cv2.cvtColor(cv2.merge([h_,s_,v_]), cv2.COLOR_HSV2BGR)
    cm  = np.array(cv2.mean(mb, mask=mask)[:3])
    diff= np.clip(np.sqrt(np.sum((mb.astype(np.float32)-cm)**2,axis=2)),0,255).astype(np.uint8)
    gr  = cv2.cvtColor(mb, cv2.COLOR_BGR2GRAY)
    hsv2= cv2.cvtColor(mb, cv2.COLOR_BGR2HSV)
    _,s2,_ = cv2.split(hsv2)
    clahe  = cv2.createCLAHE(2.0,(8,8))
    se     = clahe.apply(s2); gc = clahe.apply(gr)
    gray   = cv2.GaussianBlur(cv2.addWeighted(cv2.addWeighted(diff,.9,se,.1,0),.9,gr,.1,0),(3,3),2)
    gray_e = cv2.GaussianBlur(cv2.addWeighted(cv2.addWeighted(diff,.8,se,.2,0),.85,gc,.15,0),(3,3),2)
    H,W    = img.shape[:2]
    mn,mx  = max(8,int(H*.01)), int(H*.025)
    edge   = cv2.Canny(gray,40,140)
    candidates=[]
    for g,p2 in [(gray,29.3),(gray,26.5),(gray_e,26.5)]:
        c=cv2.HoughCircles(g,cv2.HOUGH_GRADIENT,1.2,mn*1.7,param1=38,param2=p2,minRadius=mn,maxRadius=mx)
        if c is not None:
            candidates.extend([(x,y,r,"hough") for x,y,r in np.round(c[0]).astype(int).tolist()])
    lp=np.array([110,40,30],dtype=np.uint8); up=np.array([175,255,255],dtype=np.uint8)
    pm=cv2.morphologyEx(cv2.morphologyEx(
        cv2.bitwise_and(cv2.inRange(hsv2,lp,up),mask),
        cv2.MORPH_OPEN,np.ones((3,3),np.uint8)),cv2.MORPH_CLOSE,np.ones((3,3),np.uint8))
    for cnt in cv2.findContours(pm,cv2.RETR_EXTERNAL,cv2.CHAIN_APPROX_SIMPLE)[0]:
        a=cv2.contourArea(cnt)
        if a<np.pi*(mn**2)*.35 or a>np.pi*(mx**2)*1.5: continue
        p=cv2.arcLength(cnt,True)
        if p==0 or 4*np.pi*a/(p*p)<0.45: continue
        (x,y),r=cv2.minEnclosingCircle(cnt)
        candidates.append((int(x),int(y),int(r),"purple"))
    if not candidates: return []
    balls=[]
    for x,y,r,src in candidates:
        if not(0<=y<mask.shape[0] and 0<=x<mask.shape[1]): continue
        if src=="purple":
            im=np.zeros_like(mask); cv2.circle(im,(x,y),max(2,int(r*.65)),255,-1)
            if cv2.countNonZero(cv2.bitwise_and(pm,im))/max(cv2.countNonZero(im),1)<.45: continue
        cm2=np.zeros_like(mask); cv2.circle(cm2,(x,y),r,255,-1)
        if cv2.mean(gray,mask=cm2)[0]<25: continue
        ov=cv2.countNonZero(cv2.bitwise_and(mask,cm2)); ar=cv2.countNonZero(cm2)
        if ar==0 or ov/ar<=.35: continue
        rm=np.zeros_like(mask); cv2.circle(rm,(x,y),r,255,2)
        if src!="purple" and cv2.countNonZero(cv2.bitwise_and(edge,rm))/max(2*np.pi*r,1)<.20: continue
        balls.append((x,y,r))
    balls.sort(key=lambda b:b[2],reverse=True)
    deduped=[]
    for x,y,r in balls:
        if not any(np.hypot(x-x2,y-y2)<max(r,r2) for x2,y2,r2 in deduped):
            deduped.append((x,y,r))
    if len(deduped)>=4:
        corr=[]
        for i,(x,y,r) in enumerate(deduped):
            nb=sorted([(np.hypot(x-x2,y-y2),r2) for j,(x2,y2,r2) in enumerate(deduped) if i!=j])
            lr=[r2 for _,r2 in nb[:3]]
            if lr:
                med=np.median(lr)
                if r<.7*med or r>1.2*med: r=int(med)
            corr.append((x,y,r))
        deduped=corr
    return deduped

# ─────────────────────────────────────────────────────────────
# STAGE 1 — VALIDITY
# ─────────────────────────────────────────────────────────────

def predict_validity(row, p=RULE_PARAMS):
    wr=safe_float(row.get("white_ratio")); br=safe_float(row.get("black_ratio"))
    cr=safe_float(row.get("colour_ratio")); hs=safe_float(row.get("h_std"))
    vs=safe_float(row.get("v_std")); sm=safe_float(row.get("s_median"))
    wrc=safe_float(row.get("white_ratio_center")); wrr=safe_float(row.get("white_ratio_ring"))
    cmr=wrc-wrr; score=0.0
    lc  = wr>=p["s1_cue_white_ratio_min"] and wrc>=p["s1_cue_white_center_min"] and br<=p["s1_cue_black_ratio_max"]
    ld  = br>=p["s1_dark_black_ratio_min"] and cr>=p["s1_dark_colour_ratio_min"] and vs>=p["s1_dark_v_std_min"]
    lu  = cr>=0.97 and br<=0.05 and wrc<=0.02 and wr<=0.02 and vs>=18
    la  = br>=0.30 and hs<=10 and wrc<=0.02
    lb  = br>=p["s1_black_black_ratio_min"] and cr>=p["s1_black_colour_ratio_min"] and vs>=p["s1_black_v_std_min"] and wrc<=p.get("s1_black_white_center_max",0.03)
    if lc: score+=p.get("s1_cue_score_bonus",3.0)
    if ld: score+=p["s1_dark_score_bonus"]
    if lu: score+=1.2
    if la: score-=2.0
    if lb: score+=p.get("s1_black_score_bonus",1.8)
    if wrc>=0.02: score+=1.0
    if wr>=0.02:  score+=0.5
    if hs>=12:    score+=0.6
    if hs>=20:    score+=0.6
    if vs>=20:    score+=0.8
    if vs>=40:    score+=0.5
    if cr>=0.75:  score+=0.2
    if hs<10 and not lu and not ld: score-=1.0
    if hs<5  and not lu and not ld: score-=1.2
    if sm>=180 and hs<8: score-=0.8
    if wrc<0.01 and not lu: score-=1.0
    if wr<0.01  and not lu: score-=0.6
    if cmr>0.10 and not lc: score-=0.4
    if br>0.22  and not ld: score-=0.5
    vc = "suspect" if score<=p["s1_suspect_score_thr"] else "valid_ball"
    return {"validity_class":vc, "validity_score":float(score)}

# ─────────────────────────────────────────────────────────────
# STAGE 2 — BASE COLOUR
# ─────────────────────────────────────────────────────────────

def apply_explicit_rules(row, p=RULE_PARAMS):
    br=safe_float(row.get("black_ratio")); wr=safe_float(row.get("white_ratio"))
    cr=safe_float(row.get("colour_ratio")); hm=safe_float(row.get("h_median"))
    vm=safe_float(row.get("v_median")); sm=safe_float(row.get("s_median"))
    vp=safe_float(row.get("v_p90"),vm); wrc=safe_float(row.get("white_ratio_center"))
    bt=row.get("ball_type_hint")
    if br>=p["s2_black_black_ratio_min"] and wr<=p["s2_black_white_ratio_max"] and vm<=p["s2_black_v_median_max"]: return "black"
    if bt=="stripe" and p["s2_yellow_white_ratio_lo"]<=wr<=p["s2_yellow_white_ratio_hi"] and br<=p["s2_yellow_black_ratio_max"] and cr>=p["s2_yellow_colour_ratio_min"] and hm<=p["s2_yellow_h_median_max"]: return "yellow"
    if wr>=p["s2_white_white_ratio_min"] and vp>=p["s2_white_v_p90_min"] and sm<=p["s2_white_s_median_max"] and br<=p["s2_white_black_ratio_max"] and wrc>=p["s2_white_center_min"] and wr>=wrc*p["s2_white_center_ratio"]: return "white"
    if sm>=p["s2_chrom_s_min"] and cr>=p["s2_chrom_colour_ratio_min"]:
        if hm<=p["s2_red_h_max"] or hm>=p["s2_red_h_min_wrap"]: return "red"
        if p["s2_maroon_h_lo"]<hm<=p["s2_maroon_h_hi"] and vm<=p["s2_maroon_v_max"]: return "maroon"
        if p["s2_orange_h_lo"]<hm<=p["s2_orange_h_hi"] and vm>p["s2_orange_v_min"]: return "orange"
    return None

def predict_base_colour(row):
    rule = apply_explicit_rules(row)
    if rule: return [(rule,1.0)]
    feat = get_feature_vector(row)
    return svm_predict_colour(feat)

# ─────────────────────────────────────────────────────────────
# STAGE 3 — BALL TYPE
# ─────────────────────────────────────────────────────────────

def predict_ball_type(row, colour):
    if colour=="white": return [("cue",1.0)]
    if colour=="black": return [("black",1.0)]
    feat = get_feature_vector(row)
    ranked = svm_predict_type(feat)
    # Purple override
    hs=safe_float(row.get("h_std")); cr=safe_float(row.get("colour_ratio"))
    if colour=="purple" and hs<16 and cr>0.88:
        return [("solid",1.0)]
    return ranked

def build_ranked_final(colour_ranked, type_ranked):
    options=[]
    for colour,cp in colour_ranked:
        rtypes=[("cue",1.0)] if colour=="white" else ([("black",1.0)] if colour=="black" else type_ranked)
        for btype,tp in rtypes:
            options.append({"final_label":final_label_from_parts(colour,btype),
                            "base_colour":colour,"ball_type":btype,"joint_prob":cp*tp})
    dedup={}
    for item in sorted(options,key=lambda d:d["joint_prob"],reverse=True):
        if item["final_label"] not in dedup: dedup[item["final_label"]]=item
    return list(dedup.values())

# ─────────────────────────────────────────────────────────────
# STAGE 4 — GLOBAL CONSISTENCY
# ─────────────────────────────────────────────────────────────

def combined_strength(row, p=RULE_PARAMS):
    pen = p["s4_suspect_penalty"] if row["validity_class"]=="suspect" else 0.0
    return (p["s4_w_final_conf"]*row["pred_final_conf"] +
            0.5*row["pred_colour_conf"] + 0.3*row["pred_type_conf"] +
            p["s4_w_validity_score"]*row["validity_score"] + pen)

def get_prob(row, label):
    for o in row["ranked"]:
        if o["final_label"]==label: return o["joint_prob"]
    return 0.0

def resolve_global(pred_rows, p=RULE_PARAMS):
    rows=[dict(r) for r in pred_rows]
    for r in rows:
        r["strength"]=combined_strength(r,p)
        r["final_label"]=r["pred_final_label"]
        r["final_conf"]=r["pred_final_conf"]

    for _ in range(2):
        for req in REQUIRED_UNIQUE_LABELS:
            cands=[(i,r) for i,r in enumerate(rows) if get_prob(r,req)>0]
            if not cands: continue
            cands.sort(key=lambda x: (0 if x[1]["validity_class"]=="valid_ball" else 1,
                                      -(x[1]["strength"]+2*get_prob(x[1],req))))
            wi,wr=cands[0]
            rows[wi]["final_label"]=req; rows[wi]["final_conf"]=get_prob(wr,req)

        changed=True
        while changed:
            changed=False
            grouped=defaultdict(list)
            for i,r in enumerate(rows):
                if r["final_label"]!="not_ball": grouped[r["final_label"]].append((i,r))
            for label,items in grouped.items():
                if len(items)<=1: continue
                items.sort(key=lambda x:-x[1]["strength"])
                kept=[rows[i]["final_label"] for i in range(len(rows))
                      if rows[i]["final_label"]!="not_ball" and i not in {idx for idx,_ in items[1:]}]
                for idx,row in items[1:]:
                    counts=Counter(kept)
                    for opt in row["ranked"]:
                        c=opt["final_label"]
                        if c!=label and c!="not_ball" and counts[c]<1:
                            rows[idx]["final_label"]=c; rows[idx]["final_conf"]=opt["joint_prob"]
                            changed=True; break

    for r in rows:
        if r["final_label"] in ("cue","black"): continue
        if r["validity_class"]=="suspect" and r["strength"]<p["s4_weak_suspect_strength_thr"]:
            r["final_label"]="not_ball"; r["final_conf"]=0.0
        elif r["validity_score"]<=p["s4_strong_invalid_score_thr"]:
            r["final_label"]="not_ball"; r["final_conf"]=0.0

    return rows

def predict_image(img, name):
    mask, corners = segment_table(img)
    balls = detect_balls(img, mask)
    pred_rows=[]
    for x,y,r in balls:
        roi  = crop_ball_roi(img,x,y,r)
        stats= compute_patch_statistics(roi)
        if stats is None: continue
        row={**stats,"x":int(x),"y":int(y),"r":int(r),"filename":name,"ball_type_hint":None,
             "white_center_minus_ring":stats["white_ratio_center"]-stats["white_ratio_ring"]}
        val=predict_validity(row)
        cr=predict_base_colour(row)
        tr=predict_ball_type(row,cr[0][0])
        ranked=build_ranked_final(cr,tr)
        row.update(val)
        row["pred_final_label"]=ranked[0]["final_label"] if ranked else "not_ball"
        row["pred_final_conf"]=ranked[0]["joint_prob"] if ranked else 0.0
        row["pred_colour_conf"]=cr[0][1]
        row["pred_type_conf"]=tr[0][1]
        row["ranked"]=ranked
        pred_rows.append(row)
    pred_rows=resolve_global(pred_rows)
    top_view=get_top_view(img, order_corners(corners))
    return pred_rows, top_view

# ─────────────────────────────────────────────────────────────
# MAIN
# ─────────────────────────────────────────────────────────────

def main():
    OUTPUT_DIR.mkdir(parents=True,exist_ok=True)
    TOP_VIEW_DIR.mkdir(parents=True,exist_ok=True)
    with open(INPUT_JSON) as f: image_names=json.load(f)["images"]
    results=[]
    for name in image_names:
        path=IMAGE_DIR/name
        img=cv2.imread(str(path))
        if img is None: print(f"  Could not read {name}"); continue
        try:
            pred_rows,top_view=predict_image(img,name)
        except Exception as e:
            print(f"  Error [{name}]: {e}"); pred_rows=[]; top_view=img
        cv2.imwrite(str(TOP_VIEW_DIR/name), top_view)
        balls=[{"label":r["final_label"],
                "ball_number":BALL_LABEL_TO_NUMBER.get(r["final_label"],-1),
                "x":int(r["x"]),"y":int(r["y"]),"r":int(r["r"]),
                "bbox":[int(r["x"]-r["r"]),int(r["y"]-r["r"]),
                        int(r["x"]+r["r"]),int(r["y"]+r["r"])]}
               for r in pred_rows if r["final_label"]!="not_ball"]
        results.append({"image":name,"ball_count":len(balls),"balls":balls})
        print(f"  {name}: {len(balls)} balls")
    with open(RESULTS_JSON,"w") as f: json.dump({"results":results},f,indent=2)
    print(f"Done. Results: {RESULTS_JSON}")

if __name__=="__main__":
    main()
